function invalidTransactions(transactions) {
    const trans_map = new Map();

    for (let trans of transactions) {
        let temp = trans.split(",");
        if (!trans_map.has(temp[0])) {
            trans_map.set(temp[0], []);
        }
        trans_map.get(temp[0]).push(temp);
    }

    let ans = [];

    for (let trans of transactions) {
        let temp = trans.split(",");

        if (parseInt(temp[2]) > 1000) {
            ans.push(trans);
            continue;
        }

        let others = trans_map.get(temp[0]);

        for (let other of others) {
            if (other[3] !== temp[3] && Math.abs(parseInt(other[1]) - parseInt(temp[1])) <= 60) {
                ans.push(trans);
                break;
            }
        }
    }

    return ans;
}
```


    The algorithm consists of the following steps:

1. Create a map to store transactions by names.
2. For each transaction, split it by the comma and add it to the map based on the name.
3. Initialize an empty array to store invalid transactions.
4. For each transaction, if the amount is greater than 1000, add it to the invalid transactions array.
5. Iterate through the transactions of the same name and check if the city is different and the time difference is less than or equal to 60. If yes, add the transaction to the invalid transactions array.
6. Return the invalid transactions array.

